import{c as e,Z as l,Q as r,j as i,o,m as h}from"./chunks/framework.qjzPVSkb.js";const b=JSON.parse('{"title":"ChatGPT","description":"OpenAI 出品的最通用 AI 对话助手——多模态、插件丰富、生态最全","frontmatter":{"title":"ChatGPT","description":"OpenAI 出品的最通用 AI 对话助手——多模态、插件丰富、生态最全","difficulty":"beginner"},"headers":[],"relativePath":"tools/chatgpt.md","filePath":"tools/chatgpt.md"}'),n={name:"tools/chatgpt.md"};function d(s,a,c,p,u,P){const t=l("DifficultyBadge");return r(),i("div",null,[o(t,{level:"beginner"}),a[0]||(a[0]=h('<h1 id="chatgpt" tabindex="-1">ChatGPT <a class="header-anchor" href="#chatgpt" aria-label="Permalink to &quot;ChatGPT&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>最通用的 AI 对话助手</strong>——无论你想聊天、写代码、翻译、分析文档还是画图，ChatGPT 都是最先值得一试的选择。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>OpenAI</td></tr><tr><td>价格</td><td>免费版 / Plus $20/月 / Pro $200/月</td></tr><tr><td>主要模型</td><td>GPT-4o / GPT-4o-mini / o1 / o3</td></tr><tr><td>上下文窗口</td><td>128K tokens</td></tr><tr><td>首发时间</td><td>2022 年 11 月</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="💬-多模态对话" tabindex="-1">💬 多模态对话 <a class="header-anchor" href="#💬-多模态对话" aria-label="Permalink to &quot;💬 多模态对话&quot;">​</a></h3><p>支持文字、图片、文件（PDF、Word、Excel 等）输入。你可以上传一张截图让它分析、上传一份 PDF 让它总结、上传 Excel 让它生成图表。</p><h3 id="💻-代码能力" tabindex="-1">💻 代码能力 <a class="header-anchor" href="#💻-代码能力" aria-label="Permalink to &quot;💻 代码能力&quot;">​</a></h3><p>GPT-4o 在代码生成、Debug、代码解释方面表现优异，是许多开发者的首选助手。支持几乎所有主流编程语言。</p><h3 id="🔌-gpts-与插件" tabindex="-1">🔌 GPTs 与插件 <a class="header-anchor" href="#🔌-gpts-与插件" aria-label="Permalink to &quot;🔌 GPTs 与插件&quot;">​</a></h3><p>可以创建自定义 GPTs（特定领域的专用助手），也可以调用联网搜索、DALL·E 画图、代码解释器等内置工具。</p><h3 id="🎙️-语音对话" tabindex="-1">🎙️ 语音对话 <a class="header-anchor" href="#🎙️-语音对话" aria-label="Permalink to &quot;🎙️ 语音对话&quot;">​</a></h3><p>手机 App 支持语音输入和实时语音对话，体验接近真人交流。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>生态最大</strong>：用户量最多，教程最丰富，第三方集成最广泛</li><li><strong>插件丰富</strong>：GPTs 商店里有大量专用助手，覆盖写作、编程、教育等场景</li><li><strong>多模态强</strong>：文字 + 图像 + 语音 + 文件，一个平台全搞定</li><li><strong>持续迭代</strong>：OpenAI 更新频率快，模型能力不断提升</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>免费版有使用额度限制，高峰期可能降级到低配模型</li><li>Plus 用户也有一定的 GPT-4o 调用频率限制</li><li>部分高级功能（如 o1-pro 深度推理）仅限 Pro 版</li><li>数据隐私需注意：默认情况下对话可能被用于模型训练</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 日常使用、通用场景的首选</li><li>✅ 写作、翻译、学习辅导</li><li>✅ 需要多模态能力的用户（图文混合场景）</li><li>✅ 想要丰富插件生态的用户</li><li>⚠️ 对数据隐私有极高要求的用户建议使用企业版或 API</li></ul><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/prompts/principles.html">清晰的 Prompt 怎么写</a></li><li><a href="/ai-knowledge/practices/chatgpt-coding.html">用 ChatGPT 辅助编程</a></li><li><a href="/ai-knowledge/terms/llm.html">GPT 相关术语：LLM</a>、<a href="/ai-knowledge/terms/token.html">Token</a>、<a href="/ai-knowledge/terms/context-window.html">上下文窗口</a></li><li><a href="/ai-knowledge/dev/openai-api.html">OpenAI API 入门</a> — 通过 API 调用 GPT 模型</li></ul>',22))])}const f=e(n,[["render",d]]);export{b as __pageData,f as default};
